(function(){
  function closeDropdowns(except){
    document.querySelectorAll('.dropdown.is-open').forEach(function(dropdown){
      if(dropdown !== except){
        dropdown.classList.remove('is-open');
        var button = dropdown.querySelector('button');
        if(button) button.setAttribute('aria-expanded','false');
      }
    });
  }

  function makeHeadingId(text,index,used){
    var base=(text||'phan-'+(index+1)).toLowerCase().normalize('NFD')
      .replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d')
      .replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'')||'phan-'+(index+1);
    var id=base,number=2;
    while(used[id]||document.getElementById(id)) id=base+'-'+number++;
    used[id]=true;
    return id;
  }

  function addReadingProgress(){
    if(document.querySelector('.reading-progress')) return;
    var progress=document.createElement('div');
    progress.className='reading-progress';
    progress.setAttribute('aria-hidden','true');
    progress.innerHTML='<span></span>';
    document.body.appendChild(progress);
    var bar=progress.firstElementChild;
    var update=function(){
      var max=document.documentElement.scrollHeight-window.innerHeight;
      var value=max>0?Math.min(100,Math.max(0,(window.scrollY/max)*100)):0;
      bar.style.transform='scaleX('+(value/100)+')';
    };
    update();
    window.addEventListener('scroll',update,{passive:true});
    window.addEventListener('resize',update,{passive:true});
  }

  function enhanceArticle(){
    var content=document.querySelector('.article-content');
    if(!content) return;

    var answer=content.querySelector(':scope > .answer-first');
    var hero=document.querySelector('.article-hero');
    var heroMedia=hero&&hero.querySelector('.hero-img-wrap,.article-cover-inner,img');
    if(answer&&hero&&heroMedia){
      hero.classList.add('editorial-v2');
      var mediaBlock=heroMedia.closest('.hero-img-wrap,.article-cover-inner')||heroMedia;
      hero.insertBefore(answer,mediaBlock);
    }

    var words=(content.textContent+' '+(answer?answer.textContent:'')).trim().split(/\s+/).filter(Boolean).length;
    var minutes=Math.max(1,Math.ceil(words/220));
    var meta=document.querySelector('.article-meta-top');
    if(meta&&!meta.querySelector('.reading-time')){
      var dot=document.createElement('span');
      dot.className='dot reading-time-dot';
      var time=document.createElement('span');
      time.className='reading-time';
      time.textContent=minutes+' phút đọc';
      meta.appendChild(dot);
      meta.appendChild(time);
    }

    content.querySelectorAll('table').forEach(function(table){
      if(table.parentElement&&table.parentElement.classList.contains('table-scroll')) return;
      var wrap=document.createElement('div');
      wrap.className='table-scroll';
      wrap.setAttribute('tabindex','0');
      wrap.setAttribute('role','region');
      wrap.setAttribute('aria-label','Bảng nội dung, có thể cuộn ngang');
      table.parentNode.insertBefore(wrap,table);
      wrap.appendChild(table);
    });

    var headings=Array.prototype.slice.call(content.querySelectorAll('h2')).filter(function(h){
      return !h.closest('.internal-link-hub,.seo-faq,.related-posts');
    });
    if(headings.length>1&&!content.querySelector('.article-toc')){
      var used={};
      var nav=document.createElement('nav');
      nav.className='article-toc';
      nav.setAttribute('aria-label','Mục lục bài viết');
      var details=document.createElement('details');
      details.open=!window.matchMedia('(max-width: 768px)').matches;
      var summary=document.createElement('summary');
      summary.textContent='Mục lục bài viết';
      var list=document.createElement('ol');
      headings.forEach(function(heading,index){
        if(!heading.id) heading.id=makeHeadingId(heading.textContent,index,used);
        var item=document.createElement('li');
        var link=document.createElement('a');
        link.href='#'+heading.id;
        link.textContent=heading.textContent.trim();
        item.appendChild(link);
        list.appendChild(item);
      });
      details.appendChild(summary);
      details.appendChild(list);
      nav.appendChild(details);
      var lead=content.querySelector(':scope > p:first-of-type');
      if(lead&&(!headings[0]||(lead.compareDocumentPosition(headings[0])&Node.DOCUMENT_POSITION_FOLLOWING))) lead.insertAdjacentElement('afterend',nav);
      else content.insertBefore(nav,content.firstChild);
    }
    addReadingProgress();
  }

  document.addEventListener('DOMContentLoaded', function(){
    document.querySelectorAll('.dropdown > button').forEach(function(button){
      button.type='button';
      button.setAttribute('aria-haspopup','true');
      button.setAttribute('aria-expanded','false');
      button.addEventListener('click',function(event){
        var dropdown=button.closest('.dropdown');
        if(!dropdown) return;
        var desktopHover=window.matchMedia('(hover: hover) and (pointer: fine)').matches;
        if(!desktopHover){
          event.preventDefault();
          event.stopPropagation();
          var willOpen=!dropdown.classList.contains('is-open');
          closeDropdowns(dropdown);
          dropdown.classList.toggle('is-open',willOpen);
          button.setAttribute('aria-expanded',willOpen?'true':'false');
        }
      });
    });
    document.addEventListener('click',function(event){
      if(!event.target.closest('.dropdown')) closeDropdowns();
    });
    document.addEventListener('keydown',function(event){
      if(event.key==='Escape') closeDropdowns();
    });
    enhanceArticle();
  });
})();
